// El watcher de Windows envia { path } al webhook; llega dentro de $json.body
const fullPath = ($json.body && $json.body.path) ? $json.body.path : ($json.path || "");
const filename = fullPath.split("/").pop() || "file";
const ext = filename.includes('.') ? (filename.split('.').pop() || '').toLowerCase() : '';
// localPath es la ruta REAL del archivo (ya esta en disco, no hay que descargar nada)
const localPath = fullPath;
return { json: { fileId: null, filename, ext, localPath } };

// Clasifica un archivo suelto (no comprimido). Usa ruta real y tamano leido de disco.
function safeName(name) {
  let s = (name || "file").normalize("NFC");
  s = s.replace(/[\x00-\x1F]/g, "");
  s = s.replace(/[\[\]]/g, "");
  s = s.replace(/[:*?"<>|]/g, "_");
  s = s.replace(/\s+/g, "_").trim();
  return s || "file";
}

// datos reales del flujo (no del binario, que ya no viaja)
const cf = $('Calcular filename').item.json;
const filename = cf.filename || "file";
const ext = (cf.ext || "").toLowerCase();
const localPath = cf.localPath || ("/files/" + filename);
const filenameSafe = safeName(filename);
const nombre = filenameSafe.toLowerCase();

// tamano real leido por el nodo 'Tamano real (stat)' (su stdout)
const sizeBytes = Number(($json.stdout || "0").trim()) || 0;
const sizeGB = sizeBytes / (1024 ** 3);

let rutaDestino = "/_REVISAR/";
let tipo = "desconocido";

if (ext === "pkg") {
  rutaDestino = "/packages/";
  const esDLC = /dlc|addon|add-on/.test(nombre);
  if (sizeGB > 5) tipo = "juego";
  else if (sizeGB < 1 && esDLC) tipo = "dlc";
  else tipo = "update";
} else if (ext === "iso" || ext === "bin") {
  tipo = "iso";
  if (ext === "bin" || /ps1|psx/.test(nombre)) rutaDestino = "/PSXISO/";
  else if (/ps2/.test(nombre)) rutaDestino = "/PS2ISO/";
  else if (/psp/.test(nombre)) rutaDestino = "/PSPISO/";
  else rutaDestino = "/PS3ISO/";
} else if (ext === "rap") { rutaDestino = "/exdata/"; tipo = "licencia"; }
else if (ext === "sprx") { rutaDestino = "/plugins/"; tipo = "plugin"; }
else if (ext === "self" || ext === "edat") { rutaDestino = "/game/"; tipo = "instalado"; }
else if (ext === "") { rutaDestino = "/GAMES/"; tipo = "carpeta_jb"; }

return { json: { fileId: cf.fileId, filename, filenameSafe, ext, sizeBytes, sizeGB, tipo, rutaDestino, localPath } };

// Parsea la salida de find/stat (ruta|tamano) y clasifica cada archivo extraido.
// Ya no se cargan los binarios a n8n: solo se usan ruta, nombre y tamano.
function safeName(name) {
  let s = (name || "file").normalize("NFC");
  s = s.replace(/[\x00-\x1F]/g, "");
  s = s.replace(/[\[\]]/g, "");              // quitar corchetes
  s = s.replace(/[:*?"<>|]/g, "_");
  s = s.replace(/\s+/g, "_").trim();          // espacios -> guion bajo
  return s || "file";
}

const stdout = $input.first().json.stdout || "";
const out = [];

for (const line of stdout.split("\n")) {
  const t = line.trim();
  if (!t) continue;
  const sep = t.lastIndexOf("|");
  if (sep < 0) continue;
  const localPath = t.slice(0, sep);
  const sizeBytes = Number(t.slice(sep + 1)) || 0;
  const filename = localPath.split("/").pop() || "file";
  const filenameSafe = safeName(filename);
  const nombre = filenameSafe.toLowerCase();
  const ext = filename.includes('.') ? (filename.split('.').pop() || '').toLowerCase() : '';
  const sizeGB = sizeBytes / (1024 ** 3);

  let rutaDestino = "/_REVISAR/";
  let tipo = "desconocido";

  if (ext === "pkg") {
    rutaDestino = "/packages/";
    const esDLC = /dlc|addon|add-on/.test(nombre);
    if (sizeGB > 5) tipo = "juego";
    else if (sizeGB < 1 && esDLC) tipo = "dlc";
    else tipo = "update";
  } else if (ext === "iso" || ext === "bin") {
    tipo = "iso";
    if (ext === "bin" || /ps1|psx/.test(nombre)) rutaDestino = "/PSXISO/";
    else if (/ps2/.test(nombre)) rutaDestino = "/PS2ISO/";
    else if (/psp/.test(nombre)) rutaDestino = "/PSPISO/";
    else rutaDestino = "/PS3ISO/";
  } else if (ext === "rap") { rutaDestino = "/exdata/"; tipo = "licencia"; }
  else if (ext === "sprx") { rutaDestino = "/plugins/"; tipo = "plugin"; }
  else if (ext === "self" || ext === "edat") { rutaDestino = "/game/"; tipo = "instalado"; }
  else if (ext === "" || /ps3_game/.test(nombre)) { rutaDestino = "/GAMES/"; tipo = "carpeta_jb"; }

  out.push({ json: { filename, filenameSafe, ext, sizeBytes, sizeGB, tipo, rutaDestino, localPath } });
}

return out;
